-- =================================================================
-- SEED DATA v2 – JamaaAmanah
-- 10 dons par leader × par projet = 200 dons au total
--
-- Comptes (mot de passe : Amanah2024!)
--   youssef@amanah-test.local  → super_admin
--   ibrahim@amanah-test.local  → leader (slug: ibrahim)
--   fatima@amanah-test.local   → leader (slug: fatima)
--   omar@amanah-test.local     → leader (slug: omar)
--   aicha@amanah-test.local    → leader (slug: aicha)
--
-- PIN de tous les comptes SEPA : 1234
--
-- Méthodes  : card · prelevement_sepa · cash
-- Statuts   : paid · processing · failed · cash_received · cash_remitted
--
-- Par paire (leader × projet) :
--   3× card/paid (avec balance_transaction)
--   2× prelevement_sepa/paid (avec balance_transaction)
--   1× card/processing
--   1× prelevement_sepa/processing
--   1× card/failed
--   1× cash/cash_received
--   1× cash/cash_remitted (lié à une remittance)
--
-- Usage : supabase db reset
-- =================================================================

CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- -----------------------------------------------------------------
-- PURGE
-- -----------------------------------------------------------------
TRUNCATE public.donations    RESTART IDENTITY CASCADE;
TRUNCATE public.remittances  RESTART IDENTITY CASCADE;
TRUNCATE public.balance_transactions RESTART IDENTITY CASCADE;
TRUNCATE public.donors       RESTART IDENTITY CASCADE;
TRUNCATE public.projects     RESTART IDENTITY CASCADE;
TRUNCATE public.leaders      RESTART IDENTITY CASCADE;
TRUNCATE public.profiles     RESTART IDENTITY CASCADE;
DELETE FROM auth.users WHERE email LIKE '%@amanah-test.local';


